"""Unit tests for FastSSV validation rules.

This file contains comprehensive tests for all validation rule categories:
- Anti-patterns
- Concept standardization
- Data quality
- Domain-specific
- Joins
- Temporal
"""

import pytest

from fastssv.core.base import Severity
from fastssv.rules import validate_concept_standardization


def validate_standard_concept_mapping(sql: str, dialect: str = "postgres") -> list[str]:
    """Run only the standard concept enforcement rule."""
    from fastssv.core.base import Severity
    from fastssv.core.registry import get_rule

    rule = get_rule("concept_standardization.standard_concept_enforcement")()
    violations = rule.validate(sql, dialect)

    # Also run join_path and maps_to_direction for warnings
    join_rule = get_rule("joins.join_path_validation")()
    violations.extend(join_rule.validate(sql, dialect))

    maps_rule = get_rule("joins.maps_to_direction")()
    violations.extend(maps_rule.validate(sql, dialect))

    # Convert to legacy string format
    results = []
    for v in violations:
        prefix = "Warning: " if v.severity == Severity.WARNING else ""
        results.append(f"{prefix}OMOP Semantic Rule Violation: {v.message}")

    return results


def validate_unmapped_concept_handling(sql: str, dialect: str = "postgres") -> list[str]:
    """Run only the unmapped concept handling rule."""
    from fastssv.core.base import Severity
    from fastssv.core.registry import get_rule

    rule = get_rule("data_quality.unmapped_concept_handling")()
    violations = rule.validate(sql, dialect)

    # Convert to legacy string format
    results = []
    for v in violations:
        prefix = "Warning: " if v.severity == Severity.WARNING else ""
        results.append(f"{prefix}{v.message}")

    return results


class TestStandardConceptMapping:
    """Tests for standard concept mapping rule."""

    def test_query_with_standard_concept_enforcement(self) -> None:
        """Query with standard_concept = 'S' should pass."""
        sql = """
        SELECT co.condition_concept_id
        FROM condition_occurrence co
        JOIN concept c ON co.condition_concept_id = c.concept_id
        WHERE c.standard_concept = 'S'
        """
        errors = validate_standard_concept_mapping(sql)
        assert errors == []

    def test_query_with_maps_to_relationship(self) -> None:
        """Query with 'Maps to' relationship should pass."""
        sql = """
        SELECT co.condition_concept_id
        FROM condition_occurrence co
        JOIN concept_relationship cr ON co.condition_source_concept_id = cr.concept_id_1
        WHERE cr.relationship_id = 'Maps to'
        """
        errors = validate_standard_concept_mapping(sql)
        # Should pass (uses Maps to) but may have warnings about join path
        main_errors = [e for e in errors if not e.startswith("Warning:")]
        assert main_errors == []

    def test_query_without_standard_enforcement(self) -> None:
        """Query using standard fields without enforcement should fail."""
        sql = """
        SELECT co.condition_concept_id
        FROM condition_occurrence co
        """
        errors = validate_standard_concept_mapping(sql)
        assert len(errors) > 0
        assert any("STANDARD concept fields" in e for e in errors)

    def test_query_with_standard_concept_in_join_on(self) -> None:
        """Query with standard_concept = 'S' in JOIN ON should pass."""
        sql = """
        SELECT co.condition_concept_id
        FROM condition_occurrence co
        JOIN concept c ON co.condition_concept_id = c.concept_id
            AND c.standard_concept = 'S'
        """
        errors = validate_standard_concept_mapping(sql)
        assert errors == []

    def test_query_with_in_clause(self) -> None:
        """Query with standard_concept IN ('S') should pass."""
        sql = """
        SELECT co.condition_concept_id
        FROM condition_occurrence co
        JOIN concept c ON co.condition_concept_id = c.concept_id
        WHERE c.standard_concept IN ('S')
        """
        errors = validate_standard_concept_mapping(sql)
        assert errors == []

    def test_literal_filter_on_vocab_column_does_not_satisfy_enforcement(self) -> None:
        """Regression: `WHERE ancestor_concept_id IN (...)` inside a CTE feeds a
        cohort subquery but does NOT enforce standardness on the clinical fact
        field. The rule must still fire on the outer condition_concept_id use.
        """
        sql = """
        WITH risk_cond_concepts AS (
            SELECT descendant_concept_id AS concept_id
            FROM concept_ancestor
            WHERE ancestor_concept_id IN (320128, 40481919)
        )
        SELECT DISTINCT person_id FROM condition_occurrence co
        WHERE co.condition_concept_id IN (SELECT concept_id FROM risk_cond_concepts)
        """
        errors = validate_standard_concept_mapping(sql)
        assert any("STANDARD concept fields" in e for e in errors)

    def test_literal_filter_on_standard_field_still_suppresses(self) -> None:
        """A literal filter on the actual standard concept field is intent signal —
        the user has chosen specific concept IDs. Still suppress the warning.
        """
        sql = """
        SELECT * FROM condition_occurrence
        WHERE condition_concept_id IN (201826, 201820)
        """
        errors = validate_standard_concept_mapping(sql)
        assert errors == []

    def test_direct_concept_ancestor_descendant_subquery_suppresses(self) -> None:
        """`<col> IN (SELECT descendant_concept_id FROM concept_ancestor WHERE …)`
        is the canonical OHDSI pattern for "find all members of a drug/condition
        class." concept_ancestor is, by CDM definition, a hierarchy over
        Standard Concepts only — every descendant returned is guaranteed
        standard. The rule must not require a redundant `standard_concept = 'S'`
        filter on top of this idiom.
        """
        sql = """
        SELECT EXTRACT(YEAR FROM de.drug_exposure_start_date) AS yr,
               COUNT(DISTINCT de.person_id) AS pts
        FROM drug_exposure de
        JOIN observation_period op
          ON op.person_id = de.person_id
         AND de.drug_exposure_start_date BETWEEN op.observation_period_start_date
                                             AND op.observation_period_end_date
        WHERE de.drug_concept_id IN (
            SELECT descendant_concept_id
            FROM concept_ancestor
            WHERE ancestor_concept_id = 35416207
        )
        GROUP BY yr
        """
        errors = validate_standard_concept_mapping(sql)
        assert all("STANDARD concept fields" not in e for e in errors)

    def test_direct_concept_ancestor_ancestor_subquery_suppresses(self) -> None:
        """Inverse pattern: `<col> IN (SELECT ancestor_concept_id FROM
        concept_ancestor WHERE …)`. Same standard-only guarantee."""
        sql = """
        SELECT co.person_id
        FROM condition_occurrence co
        WHERE co.condition_concept_id IN (
            SELECT ancestor_concept_id
            FROM concept_ancestor
            WHERE descendant_concept_id = 201826
        )
        """
        errors = validate_standard_concept_mapping(sql)
        assert all("STANDARD concept fields" not in e for e in errors)

    def test_subquery_from_unrelated_table_still_fires(self) -> None:
        """Suppression must be specific to concept_ancestor, not any subquery.
        `<col> IN (SELECT some_id FROM some_other_table)` carries no standard-
        concept guarantee."""
        sql = """
        SELECT co.person_id
        FROM condition_occurrence co
        WHERE co.condition_concept_id IN (
            SELECT concept_id FROM custom_lookup_table
        )
        """
        errors = validate_standard_concept_mapping(sql)
        assert any("STANDARD concept fields" in e for e in errors)

    def test_inline_join_to_concept_ancestor_descendant_suppresses(self) -> None:
        """The JOIN form of the cohort idiom — equally idiomatic in OHDSI:

            FROM drug_exposure de
            JOIN concept_ancestor ca ON de.drug_concept_id = ca.descendant_concept_id
            WHERE ca.ancestor_concept_id = <id>

        carries the same standard-concept guarantee as the IN-subquery form
        (concept_ancestor is a hierarchy over Standard Concepts only). The
        rule must not require a redundant `standard_concept = 'S'` filter on
        top of this pattern.
        """
        sql = """
        SELECT EXTRACT(YEAR FROM de.drug_exposure_start_date) AS yr,
               COUNT(DISTINCT de.person_id) AS pts
        FROM drug_exposure de
        JOIN concept_ancestor ca
          ON de.drug_concept_id = ca.descendant_concept_id
        WHERE ca.ancestor_concept_id = 43027253
        GROUP BY yr
        """
        errors = validate_standard_concept_mapping(sql)
        assert all("STANDARD concept fields" not in e for e in errors)

    def test_inline_join_to_concept_ancestor_ancestor_suppresses(self) -> None:
        """Inverse direction: clinical column joined to ancestor_concept_id."""
        sql = """
        SELECT co.person_id
        FROM condition_occurrence co
        JOIN concept_ancestor ca
          ON co.condition_concept_id = ca.ancestor_concept_id
        WHERE ca.descendant_concept_id = 201826
        """
        errors = validate_standard_concept_mapping(sql)
        assert all("STANDARD concept fields" not in e for e in errors)

    def test_inline_join_to_concept_ancestor_unrelated_column_still_fires(self) -> None:
        """A JOIN to concept_ancestor that doesn't connect a clinical *_concept_id
        column to descendant/ancestor_concept_id provides no standard-concept
        guarantee for the clinical column. Defensive case: don't suppress just
        because concept_ancestor appears in the FROM list."""
        sql = """
        SELECT co.person_id
        FROM condition_occurrence co
        JOIN concept_ancestor ca ON ca.min_levels_of_separation = 0
        WHERE co.condition_concept_id = ca.descendant_concept_id - 1
        """
        errors = validate_standard_concept_mapping(sql)
        assert any("STANDARD concept fields" in e for e in errors)

    def test_chained_join_clinical_concept_concept_ancestor_suppresses(self) -> None:
        """The chained-JOIN form of the cohort idiom — clinical fact table
        joined to concept, and concept joined to concept_ancestor — has the
        same standard-concept guarantee as the direct-JOIN and IN-subquery
        forms (concept_ancestor descendants are standard by CDM definition).
        Users adopt this shape when they also want concept's columns in the
        SELECT list. The rule must not require a redundant
        `concept.standard_concept = 'S'` filter on top.
        """
        sql = """
        SELECT COUNT(DISTINCT person.person_id)
        FROM condition_occurrence
        INNER JOIN person ON condition_occurrence.person_id = person.person_id
        INNER JOIN concept ON condition_occurrence.condition_concept_id = concept.concept_id
        INNER JOIN concept_ancestor ON concept.concept_id = concept_ancestor.descendant_concept_id
        WHERE concept_ancestor.ancestor_concept_id = 320128
        """
        errors = validate_standard_concept_mapping(sql)
        assert all("STANDARD concept fields" not in e for e in errors)

    def test_chained_join_via_ancestor_direction_suppresses(self) -> None:
        """Inverse direction of the chain — concept.concept_id joined to
        concept_ancestor.ancestor_concept_id."""
        sql = """
        SELECT co.person_id
        FROM condition_occurrence co
        JOIN concept c ON co.condition_concept_id = c.concept_id
        JOIN concept_ancestor ca ON c.concept_id = ca.ancestor_concept_id
        WHERE ca.descendant_concept_id = 201826
        """
        errors = validate_standard_concept_mapping(sql)
        assert all("STANDARD concept fields" not in e for e in errors)

    def test_broken_chain_concept_to_concept_ancestor_unrelated_column_still_fires(self) -> None:
        """Defensive: if the chain is broken — e.g. concept→concept_ancestor on
        a column other than descendant/ancestor_concept_id — the standard-
        concept guarantee no longer holds and the rule must still fire."""
        sql = """
        SELECT co.person_id
        FROM condition_occurrence co
        JOIN concept c ON co.condition_concept_id = c.concept_id
        JOIN concept_ancestor ca ON ca.min_levels_of_separation = c.concept_id
        WHERE ca.ancestor_concept_id = 320128
        """
        errors = validate_standard_concept_mapping(sql)
        assert any("STANDARD concept fields" in e for e in errors)

    def test_subquery_selecting_non_id_column_from_concept_ancestor_still_fires(self) -> None:
        """Defensive: if the subquery selects something that's *not*
        descendant_concept_id / ancestor_concept_id from concept_ancestor (e.g.
        min_levels_of_separation), don't suppress — the standard-concept
        guarantee comes from the id columns, not arbitrary projections."""
        sql = """
        SELECT co.person_id
        FROM condition_occurrence co
        WHERE co.condition_concept_id IN (
            SELECT min_levels_of_separation FROM concept_ancestor
        )
        """
        errors = validate_standard_concept_mapping(sql)
        assert any("STANDARD concept fields" in e for e in errors)

    def test_unqualified_column_in_single_table_still_fires(self) -> None:
        """The homepage 'Missing standard concept' example uses an unqualified
        ``condition_concept_id`` reference. Detector must attribute unqualified
        columns to the unique standard-field-owning table in scope, otherwise
        the example silently produces zero violations and the warning never
        appears in the UI.
        """
        sql = """
        WITH risk_concepts AS (
            SELECT descendant_concept_id AS concept_id
            FROM concept_ancestor
            WHERE ancestor_concept_id = 201820
        )
        SELECT DISTINCT person_id
        FROM condition_occurrence
        WHERE condition_concept_id IN (SELECT concept_id FROM risk_concepts)
        """
        errors = validate_standard_concept_mapping(sql)
        assert any("STANDARD concept fields" in e for e in errors)


class TestJoinPathValidation:
    """Tests for the join-path validation rule, specifically the
    scalar/IN-subquery suppression added to avoid join-shaped warnings on
    queries that don't actually JOIN concept to clinical tables."""

    def _run_rule(self, sql: str) -> list:
        from fastssv.core.registry import get_rule
        rule = get_rule("joins.join_path_validation")()
        return rule.validate(sql)

    def test_concept_in_scalar_subquery_does_not_fire(self) -> None:
        """`WHERE p.gender_concept_id = (SELECT concept_id FROM concept WHERE …)`
        is a value-lookup pattern, not a JOIN. The rule's intent ("concept
        properly linked to clinical via concept_id") doesn't apply — there's
        no JOIN to validate. The relevant concerns (deprecated concepts,
        whitespace, lookup ambiguity) are covered by other rules.
        """
        sql = """
        SELECT COUNT(DISTINCT co.person_id)
        FROM condition_occurrence co
        JOIN person p ON p.person_id = co.person_id
        WHERE co.condition_concept_id = 320128
          AND p.gender_concept_id = (
              SELECT concept_id
              FROM concept
              WHERE concept_name = 'Female'
                AND domain_id = 'Gender'
          )
        """
        violations = self._run_rule(sql)
        assert violations == []

    def test_concept_in_in_subquery_does_not_fire(self) -> None:
        """Same suppression for IN-subquery shape."""
        sql = """
        SELECT de.person_id
        FROM drug_exposure de
        WHERE de.drug_concept_id IN (
            SELECT concept_id FROM concept
            WHERE vocabulary_id = 'RxNorm' AND standard_concept = 'S'
        )
        """
        violations = self._run_rule(sql)
        assert violations == []

    def test_concept_joined_to_clinical_with_proper_concept_id_link_passes(self) -> None:
        """Sanity: when concept IS joined to a clinical table on concept_id,
        the rule (correctly) doesn't fire — the join path is valid."""
        sql = """
        SELECT co.person_id
        FROM condition_occurrence co
        JOIN concept c ON co.condition_concept_id = c.concept_id
        WHERE c.standard_concept = 'S'
        """
        violations = self._run_rule(sql)
        assert violations == []

    def test_concept_joined_outside_subquery_still_fires(self) -> None:
        """When concept is joined to a clinical table but on the wrong column
        (no concept_id linkage), the rule must still fire. The suppression
        only applies to subquery-only usage, not to actual JOINs."""
        sql = """
        SELECT co.person_id
        FROM condition_occurrence co
        JOIN concept c ON co.condition_concept_id = c.domain_id
        """
        violations = self._run_rule(sql)
        assert len(violations) > 0
        assert any("concept" in v.message for v in violations)


class TestUnmappedConceptHandling:
    """Tests for concept_id = 0 handling rule."""

    def test_specific_concept_id_equality_implicitly_excludes_zero(self) -> None:
        """Query with `col = <non-zero>` implicitly excludes 0 and should not warn."""
        sql = """
        SELECT * FROM condition_occurrence
        WHERE condition_concept_id = 201826
        """
        warnings = validate_unmapped_concept_handling(sql)
        assert warnings == []

    def test_concept_id_with_greater_than_zero(self) -> None:
        """Query with > 0 should not warn."""
        sql = """
        SELECT * FROM condition_occurrence
        WHERE condition_concept_id = 201826 AND condition_concept_id > 0
        """
        warnings = validate_unmapped_concept_handling(sql)
        assert warnings == []

    def test_concept_id_with_not_equal_zero(self) -> None:
        """Query with != 0 should not warn."""
        sql = """
        SELECT * FROM condition_occurrence
        WHERE condition_concept_id = 201826 AND condition_concept_id != 0
        """
        warnings = validate_unmapped_concept_handling(sql)
        assert warnings == []

    def test_in_clause_with_non_zero_literals_implicitly_excludes_zero(self) -> None:
        """Query with `col IN (non-zero, non-zero)` implicitly excludes 0 and should not warn."""
        sql = """
        SELECT * FROM condition_occurrence
        WHERE condition_concept_id IN (201826, 201820)
        """
        warnings = validate_unmapped_concept_handling(sql)
        assert warnings == []

    def test_person_gender_concept_id_equality_no_warn(self) -> None:
        """Regression: `person.gender_concept_id = 8532` should not warn (ATLAS-style query)."""
        sql = """
        SELECT COUNT(person_id) FROM person
        WHERE gender_concept_id = 8532
        """
        warnings = validate_unmapped_concept_handling(sql)
        assert warnings == []

    def test_no_specific_filter(self) -> None:
        """Query without specific concept_id filter should not warn."""
        sql = """
        SELECT co.* FROM condition_occurrence co
        JOIN concept c ON co.condition_concept_id = c.concept_id
        """
        warnings = validate_unmapped_concept_handling(sql)
        assert warnings == []

    def test_non_clinical_table(self) -> None:
        """Query on concept table should not warn."""
        sql = """
        SELECT * FROM concept
        WHERE concept_id = 201826
        """
        warnings = validate_unmapped_concept_handling(sql)
        assert warnings == []


class TestCombinedSemanticValidation:
    """Tests for combined semantic validation."""

    def test_valid_query(self) -> None:
        """A properly constructed query should pass all validations."""
        sql = """
        SELECT co.condition_concept_id, c.concept_name
        FROM condition_occurrence co
        JOIN concept_ancestor ca ON co.condition_concept_id = ca.descendant_concept_id
        JOIN concept c ON co.condition_concept_id = c.concept_id
        WHERE ca.ancestor_concept_id = 201826
        AND co.condition_concept_id > 0
        AND c.standard_concept = 'S'
        AND c.invalid_reason IS NULL
        AND c.domain_id = 'Condition'
        """
        errors = validate_concept_standardization(sql)
        assert errors == []

    def test_invalid_sql(self) -> None:
        """Invalid SQL should return parse error."""
        sql = "SELECT FROM WHERE"
        errors = validate_concept_standardization(sql)
        assert len(errors) > 0
        assert any("parse error" in e.lower() or "error" in e.lower() for e in errors)


class TestObservationPeriodAnchoring:
    """Tests for observation period anchoring rule (temporal constraints)."""

    def _validate_temporal(self, sql: str, dialect: str = "postgres") -> list[str]:
        """Run only the observation period anchoring rule."""
        from fastssv.core.base import Severity
        from fastssv.core.registry import get_rule

        rule = get_rule("temporal.observation_period_anchoring")()
        violations = rule.validate(sql, dialect)

        results = []
        for v in violations:
            prefix = "Warning: " if v.severity == Severity.WARNING else ""
            results.append(f"{prefix}{v.message}")
        return results

    def test_temporal_filter_without_observation_period_should_error(self) -> None:
        """Query with date filter but no observation_period should error."""
        sql = """
        SELECT * FROM condition_occurrence
        WHERE condition_start_date >= '2020-01-01'
        """
        errors = self._validate_temporal(sql)
        assert len(errors) > 0
        assert any("observation_period" in e for e in errors)

    def test_temporal_filter_with_observation_period_should_pass(self) -> None:
        """Query with date filter AND observation_period join should pass."""
        sql = """
        SELECT co.*
        FROM condition_occurrence co
        JOIN observation_period op ON co.person_id = op.person_id
        WHERE co.condition_start_date >= '2020-01-01'
        """
        errors = self._validate_temporal(sql)
        # Should pass (has observation_period join on person_id)
        main_errors = [e for e in errors if not e.startswith("Warning:")]
        assert main_errors == []

    def test_multiple_date_filters_without_observation_period(self) -> None:
        """Query with multiple date filters should error without observation_period."""
        sql = """
        SELECT * FROM drug_exposure
        WHERE drug_exposure_start_date >= '2020-01-01'
        AND drug_exposure_end_date <= '2020-12-31'
        """
        errors = self._validate_temporal(sql)
        assert len(errors) > 0

    def test_date_comparison_between_tables(self) -> None:
        """Query comparing dates between tables should require observation_period."""
        sql = """
        SELECT co.*, de.*
        FROM condition_occurrence co
        JOIN drug_exposure de ON co.person_id = de.person_id
        WHERE de.drug_exposure_start_date > co.condition_start_date
        """
        errors = self._validate_temporal(sql)
        assert len(errors) > 0
        assert any("observation_period" in e for e in errors)

    def test_no_temporal_constraints_should_not_trigger(self) -> None:
        """Query without temporal constraints should not trigger the rule."""
        sql = """
        SELECT * FROM condition_occurrence
        WHERE condition_concept_id = 12345
        """
        errors = self._validate_temporal(sql)
        assert errors == []

    def test_observation_period_in_cte_should_pass(self) -> None:
        """Query using observation_period in CTE should pass."""
        sql = """
        WITH valid_patients AS (
            SELECT co.*, op.observation_period_start_date, op.observation_period_end_date
            FROM condition_occurrence co
            JOIN observation_period op ON co.person_id = op.person_id
            WHERE co.condition_start_date BETWEEN op.observation_period_start_date 
                AND op.observation_period_end_date
        )
        SELECT * FROM valid_patients
        WHERE condition_start_date >= '2020-01-01'
        """
        errors = self._validate_temporal(sql)
        main_errors = [e for e in errors if not e.startswith("Warning:")]
        assert main_errors == []

    def test_washout_period_pattern_should_require_observation_period(self) -> None:
        """Washout period pattern (NOT EXISTS with date) should require observation_period."""
        sql = """
        SELECT co.*
        FROM condition_occurrence co
        WHERE NOT EXISTS (
            SELECT 1 FROM drug_exposure de
            WHERE de.person_id = co.person_id
            AND de.drug_exposure_start_date < co.condition_start_date
        )
        """
        errors = self._validate_temporal(sql)
        assert len(errors) > 0

    def test_vocabulary_only_query_should_not_require_observation_period(self) -> None:
        """Regression: concept-discovery queries over vocabulary tables have no
        clinical fact table and no person dimension, so observation_period
        anchoring is structurally impossible and should not be flagged — even
        if the query compares date columns like concept.valid_start_date /
        valid_end_date that happen to look temporal."""
        sql = """
        SELECT DISTINCT C.concept_id, C.concept_name
        FROM concept C
        LEFT JOIN concept_synonym S ON C.concept_id = S.concept_id
        WHERE C.vocabulary_id IN ('LOINC', 'UCUM')
          AND C.standard_concept = 'S'
          AND getdate() >= C.valid_start_date
          AND my_date <= C.valid_end_date
        """
        errors = self._validate_temporal(sql)
        op_errors = [e for e in errors if "observation_period" in e]
        assert op_errors == []


class TestEdgeCases:
    """Edge cases for semantic validation."""

    def test_cte_query(self) -> None:
        """Query with CTE should be handled correctly."""
        sql = """
        WITH diabetic_patients AS (
            SELECT co.person_id, co.condition_concept_id
            FROM condition_occurrence co
            JOIN concept_ancestor ca ON co.condition_concept_id = ca.descendant_concept_id
            WHERE ca.ancestor_concept_id = 201826
            AND co.condition_concept_id > 0
        )
        SELECT dp.*, c.concept_name
        FROM diabetic_patients dp
        JOIN concept c ON dp.condition_concept_id = c.concept_id
        WHERE c.standard_concept = 'S'
        AND c.invalid_reason IS NULL
        """
        errors = validate_concept_standardization(sql)
        # May have warnings but shouldn't have main errors
        main_errors = [e for e in errors if "Violation" in e]
        assert main_errors == []

    def test_multiple_clinical_tables(self) -> None:
        """Query joining multiple clinical tables."""
        sql = """
        SELECT co.condition_concept_id, de.drug_concept_id
        FROM condition_occurrence co
        JOIN drug_exposure de ON co.person_id = de.person_id
        JOIN concept c1 ON co.condition_concept_id = c1.concept_id
        JOIN concept c2 ON de.drug_concept_id = c2.concept_id
        WHERE c1.standard_concept = 'S'
        AND c2.standard_concept = 'S'
        """
        errors = validate_standard_concept_mapping(sql)
        assert errors == []

    def test_subquery(self) -> None:
        """Query with subquery should be handled."""
        sql = """
        SELECT * FROM condition_occurrence
        WHERE condition_concept_id IN (
            SELECT concept_id FROM concept
            WHERE vocabulary_id = 'SNOMED' AND standard_concept = 'S'
        )
        """
        errors = validate_standard_concept_mapping(sql)
        # The subquery has standard_concept = 'S', so this should pass
        assert errors == []


class TestInvalidReasonEnforcement:
    """Tests for invalid_reason enforcement rule (OMOP_501).

    The rule is gated behind strict mode (silent in default mode), so the
    helper installs ``ValidationContext(strict_mode=True)`` for the
    duration of each rule call. The detection-logic assertions below
    therefore exercise the rule's behavior *when enabled*.
    """

    def _run_invalid_reason_rule(self, sql: str) -> list[str]:
        """Run invalid_reason enforcement rule (in strict mode) and return formatted violations."""
        from fastssv.core.base import Severity
        from fastssv.core.registry import get_rule
        from fastssv.core.validation_context import with_strict_mode

        rule = get_rule("concept_standardization.invalid_reason_enforcement")()
        with with_strict_mode(True):
            violations = rule.validate(sql)

        # Convert to legacy string format. Severity may be ERROR in strict
        # mode (escalated by should_escalate_rule) — preserve the legacy
        # "Warning:" prefix on warnings only.
        results = []
        for v in violations:
            prefix = "Warning: " if v.severity == Severity.WARNING else ""
            results.append(f"{prefix}OMOP Semantic Rule Violation: {v.message}")

        return results

    # Tests for tables WITH invalid_reason column (ERROR if missing)

    def test_concept_table_without_invalid_reason_filter(self) -> None:
        """Query on concept table without invalid_reason should WARN (best practice)."""
        sql = """
        SELECT concept_id, concept_name
        FROM concept
        WHERE domain_id = 'Drug'
        """
        errors = self._run_invalid_reason_rule(sql)
        assert len(errors) > 0
        assert any("concept" in e and "invalid_reason" in e for e in errors)
        # Should be WARNING (best practice), not error
        assert all(e.startswith("Warning:") for e in errors)

    def test_concept_table_with_invalid_reason_is_null(self) -> None:
        """Query with invalid_reason IS NULL should pass."""
        sql = """
        SELECT concept_id, concept_name
        FROM concept
        WHERE domain_id = 'Drug'
        AND invalid_reason IS NULL
        """
        errors = self._run_invalid_reason_rule(sql)
        assert errors == []

    def test_concept_table_with_invalid_reason_is_not_null(self) -> None:
        """Query explicitly checking for invalid concepts should pass."""
        sql = """
        SELECT concept_id, concept_name, invalid_reason
        FROM concept
        WHERE invalid_reason IS NOT NULL
        """
        errors = self._run_invalid_reason_rule(sql)
        assert errors == []

    def test_concept_relationship_without_invalid_reason(self) -> None:
        """Query on concept_relationship without invalid_reason should ERROR."""
        sql = """
        SELECT concept_id_1, concept_id_2
        FROM concept_relationship
        WHERE relationship_id = 'Maps to'
        """
        errors = self._run_invalid_reason_rule(sql)
        assert len(errors) > 0
        assert any("concept_relationship" in e for e in errors)

    def test_concept_relationship_with_invalid_reason(self) -> None:
        """Query on concept_relationship with invalid_reason should pass."""
        sql = """
        SELECT concept_id_1, concept_id_2
        FROM concept_relationship
        WHERE relationship_id = 'Maps to'
        AND invalid_reason IS NULL
        """
        errors = self._run_invalid_reason_rule(sql)
        assert errors == []

    # Tests for derived tables WITHOUT invalid_reason column (WARNING)

    def test_concept_ancestor_without_concept_join(self) -> None:
        """Query on concept_ancestor without concept join should WARN."""
        sql = """
        SELECT descendant_concept_id
        FROM concept_ancestor
        WHERE ancestor_concept_id = 201826
        """
        errors = self._run_invalid_reason_rule(sql)
        assert len(errors) > 0
        assert any("concept_ancestor" in e for e in errors)
        # Should be WARNING, not error
        assert any(e.startswith("Warning:") for e in errors)

    def test_concept_ancestor_with_concept_join(self) -> None:
        """Query on concept_ancestor with proper concept join should pass."""
        sql = """
        SELECT ca.descendant_concept_id
        FROM concept_ancestor ca
        JOIN concept c ON c.concept_id = ca.descendant_concept_id
        WHERE ca.ancestor_concept_id = 201826
        AND c.invalid_reason IS NULL
        """
        errors = self._run_invalid_reason_rule(sql)
        assert errors == []

    def test_concept_ancestor_inline_join_to_clinical_warns(self) -> None:
        """The JOIN form of the cohort idiom — concept_ancestor JOINed against
        a clinical fact table on its descendant_concept_id — must trigger the
        rule. Semantically equivalent to the IN-subquery form, but previously
        slid past `_derived_table_in_from` because sqlglot stores joined
        tables under `select.args['joins']`, not under the From node.
        """
        sql = """
        SELECT EXTRACT(YEAR FROM de.drug_exposure_start_date) AS yr,
               COUNT(DISTINCT de.person_id) AS pts
        FROM drug_exposure de
        JOIN concept_ancestor ca
          ON de.drug_concept_id = ca.descendant_concept_id
        WHERE ca.ancestor_concept_id = 43027253
        GROUP BY yr
        """
        errors = self._run_invalid_reason_rule(sql)
        assert len(errors) > 0
        assert any("concept_ancestor" in e for e in errors)

    def test_concept_ancestor_inline_join_with_concept_invalid_reason_passes(self) -> None:
        """Same JOIN-form cohort idiom, but with concept joined and
        invalid_reason filtered — should pass."""
        sql = """
        SELECT de.person_id
        FROM drug_exposure de
        JOIN concept_ancestor ca
          ON de.drug_concept_id = ca.descendant_concept_id
        JOIN concept c
          ON c.concept_id = ca.descendant_concept_id
        WHERE ca.ancestor_concept_id = 43027253
          AND c.invalid_reason IS NULL
        """
        errors = self._run_invalid_reason_rule(sql)
        assert errors == []

    def test_concept_ancestor_chained_join_through_concept_warns(self) -> None:
        """The chained-JOIN form of the cohort idiom — clinical fact table
        joined to concept, and concept joined to concept_ancestor — must
        trigger the rule. Symmetric to the IN-subquery and direct-JOIN
        forms. The previous "JOIN counterparty must be non-vocabulary"
        heuristic incorrectly classified this as a lookup join because the
        counterparty was `concept`; the new "literal filter on concept_
        ancestor's hierarchy" heuristic gets it right.
        """
        sql = """
        SELECT COUNT(DISTINCT person.person_id)
        FROM condition_occurrence
        INNER JOIN concept ON condition_occurrence.condition_concept_id = concept.concept_id
        INNER JOIN concept_ancestor ON concept.concept_id = concept_ancestor.descendant_concept_id
        WHERE concept_ancestor.ancestor_concept_id = 320128
        """
        errors = self._run_invalid_reason_rule(sql)
        assert len(errors) > 0
        assert any("concept_ancestor" in e for e in errors)

    def test_concept_ancestor_chained_join_with_invalid_reason_passes(self) -> None:
        """Same chained-JOIN cohort idiom, but with concept's invalid_reason
        filtered — should pass. The whole-tree walk for
        `_has_concept_join_with_invalid_reason_filter` correctly suppresses
        when the filter is present anywhere in the query, not just at the
        outer level."""
        sql = """
        SELECT person_id
        FROM condition_occurrence co
        JOIN concept c ON co.condition_concept_id = c.concept_id
        JOIN concept_ancestor ca ON c.concept_id = ca.descendant_concept_id
        WHERE ca.ancestor_concept_id = 320128
          AND c.invalid_reason IS NULL
        """
        errors = self._run_invalid_reason_rule(sql)
        assert errors == []

    def test_concept_ancestor_multi_ancestor_in_list_warns(self) -> None:
        """`WHERE ca.ancestor_concept_id IN (a, b, c, d)` is also a source
        signal — the user is selecting via the hierarchy, just from multiple
        ancestor entry points."""
        sql = """
        SELECT de.person_id
        FROM drug_exposure de
        JOIN concept_ancestor ca ON de.drug_concept_id = ca.descendant_concept_id
        WHERE ca.ancestor_concept_id IN (974166, 1115008, 1308216)
        """
        errors = self._run_invalid_reason_rule(sql)
        assert len(errors) > 0
        assert any("concept_ancestor" in e for e in errors)

    def test_concept_ancestor_lookup_join_to_concept_does_not_fire(self) -> None:
        """When concept_ancestor is joined against another vocabulary table
        (concept→concept_ancestor lookup), the join is decorative, not a
        cohort source. The existing rule already handles this correctly via
        primary-FROM detection; verifying the new branch doesn't regress it.
        """
        sql = """
        SELECT c.concept_name, ca.descendant_concept_id
        FROM concept c
        JOIN concept_ancestor ca ON ca.ancestor_concept_id = c.concept_id
        WHERE c.concept_id = 192671
          AND c.invalid_reason IS NULL
        """
        errors = self._run_invalid_reason_rule(sql)
        # No concept_ancestor warning — concept_ancestor is a lookup here, not
        # a source. The concept-table side has invalid_reason filtered, so no
        # other warning should fire either.
        assert all("concept_ancestor" not in e for e in errors)

    def test_concept_synonym_without_concept_join(self) -> None:
        """Query on concept_synonym without concept join should WARN."""
        sql = """
        SELECT concept_id, concept_synonym_name
        FROM concept_synonym
        WHERE concept_synonym_name LIKE '%diabetes%'
        """
        errors = self._run_invalid_reason_rule(sql)
        assert len(errors) > 0
        assert any("concept_synonym" in e for e in errors)
        assert any(e.startswith("Warning:") for e in errors)

    def test_drug_strength_without_concept_join(self) -> None:
        """Query on drug_strength without concept join should WARN."""
        sql = """
        SELECT drug_concept_id, ingredient_concept_id
        FROM drug_strength
        """
        errors = self._run_invalid_reason_rule(sql)
        assert len(errors) > 0
        assert any("drug_strength" in e for e in errors)

    # Tests for clinical tables (NO check needed)

    def test_clinical_table_no_invalid_reason_needed(self) -> None:
        """Query on clinical table should not require invalid_reason."""
        sql = """
        SELECT person_id, condition_concept_id
        FROM condition_occurrence
        WHERE condition_concept_id = 201826
        """
        errors = self._run_invalid_reason_rule(sql)
        assert errors == []

    def test_multiple_clinical_tables_no_check(self) -> None:
        """Query on multiple clinical tables should not require invalid_reason."""
        sql = """
        SELECT co.person_id, de.drug_concept_id
        FROM condition_occurrence co
        JOIN drug_exposure de ON co.person_id = de.person_id
        """
        errors = self._run_invalid_reason_rule(sql)
        assert errors == []

    # Edge cases

    def test_invalid_reason_in_join_on_clause(self) -> None:
        """invalid_reason filter in JOIN ON clause should pass."""
        sql = """
        SELECT co.condition_concept_id
        FROM condition_occurrence co
        JOIN concept c
            ON co.condition_concept_id = c.concept_id
            AND c.invalid_reason IS NULL
        """
        errors = self._run_invalid_reason_rule(sql)
        assert errors == []

    def test_mixed_vocabulary_and_clinical_tables_with_standard_filter_passes(self) -> None:
        """Query that already filters standard_concept = 'S' has effectively narrowed
        to valid concepts (standard concepts are almost always valid in OMOP), so the
        additional invalid_reason check is redundant — no warning."""
        sql = """
        SELECT co.person_id, c.concept_name
        FROM condition_occurrence co
        JOIN concept c ON co.condition_concept_id = c.concept_id
        WHERE c.standard_concept = 'S'
        """
        errors = self._run_invalid_reason_rule(sql)
        assert errors == []

    def test_mixed_vocabulary_and_clinical_tables_without_standard_filter_warns(self) -> None:
        """Without standard_concept filter, source-column filter (domain_id) still warns."""
        sql = """
        SELECT co.person_id, c.concept_name
        FROM condition_occurrence co
        JOIN concept c ON co.condition_concept_id = c.concept_id
        WHERE c.domain_id = 'Condition'
        """
        errors = self._run_invalid_reason_rule(sql)
        assert len(errors) > 0
        assert any("concept" in e for e in errors)

    def test_concept_join_as_lookup_only_should_not_warn(self) -> None:
        """Joining concept purely to decode concept_id -> concept_name (no filters on
        concept.vocabulary_id / domain_id / etc.) is lookup usage, not source usage,
        and should not trigger the invalid_reason warning."""
        sql = """
        SELECT p.gender_concept_id, c.concept_name AS gender_name, COUNT(p.person_id)
        FROM person p
        JOIN concept c ON p.gender_concept_id = c.concept_id
        GROUP BY p.gender_concept_id, c.concept_name
        """
        errors = self._run_invalid_reason_rule(sql)
        assert errors == []

    def test_subquery_with_concept_table(self) -> None:
        """Subquery using concept table should be checked."""
        sql = """
        SELECT * FROM condition_occurrence
        WHERE condition_concept_id IN (
            SELECT concept_id FROM concept
            WHERE vocabulary_id = 'SNOMED'
        )
        """
        errors = self._run_invalid_reason_rule(sql)
        # Should flag the concept table in the subquery
        assert len(errors) > 0

    def test_cte_with_concept_ancestor(self) -> None:
        """CTE using concept_ancestor should be checked."""
        sql = """
        WITH descendants AS (
            SELECT descendant_concept_id
            FROM concept_ancestor
            WHERE ancestor_concept_id = 201826
        )
        SELECT * FROM descendants
        """
        errors = self._run_invalid_reason_rule(sql)
        # Should warn about concept_ancestor
        assert len(errors) > 0
        assert any("concept_ancestor" in e for e in errors)

    def test_no_vocabulary_tables_used(self) -> None:
        """Query without any vocabulary tables should not be checked."""
        sql = """
        SELECT person_id, condition_start_date
        FROM condition_occurrence
        WHERE condition_start_date > '2020-01-01'
        """
        errors = self._run_invalid_reason_rule(sql)
        assert errors == []


class TestDomainSegregation:
    """Tests for the domain segregation rule (now merged into concept_domain_validation)."""

    def _run_rule(self, sql: str, dialect: str = "postgres") -> list:
        from fastssv.core.base import Severity
        from fastssv.core.registry import get_rule

        rule = get_rule("concept_standardization.concept_domain_validation")()
        violations = rule.validate(sql, dialect)
        results = []
        for v in violations:
            prefix = "Warning: " if v.severity == Severity.WARNING else "Error: "
            results.append(f"{prefix}{v.message}")
        return results

    # --- Correct domain filter -> no violation ---

    def test_condition_occurrence_correct_domain(self) -> None:
        """condition_occurrence joined to concept with domain_id = 'Condition' should pass."""
        sql = """
        SELECT co.condition_concept_id
        FROM condition_occurrence co
        JOIN concept c ON co.condition_concept_id = c.concept_id
        WHERE c.domain_id = 'Condition'
        AND c.standard_concept = 'S'
        """
        errors = self._run_rule(sql)
        assert errors == []

    def test_drug_exposure_correct_domain(self) -> None:
        """drug_exposure joined to concept with domain_id = 'Drug' should pass."""
        sql = """
        SELECT de.drug_concept_id
        FROM drug_exposure de
        JOIN concept c ON de.drug_concept_id = c.concept_id
        WHERE c.domain_id = 'Drug'
        """
        errors = self._run_rule(sql)
        assert errors == []

    def test_procedure_occurrence_correct_domain(self) -> None:
        """procedure_occurrence with domain_id = 'Procedure' should pass."""
        sql = """
        SELECT po.procedure_concept_id
        FROM procedure_occurrence po
        JOIN concept c ON po.procedure_concept_id = c.concept_id
        WHERE c.domain_id = 'Procedure'
        AND c.standard_concept = 'S'
        """
        errors = self._run_rule(sql)
        assert errors == []

    def test_measurement_correct_domain(self) -> None:
        """measurement with domain_id = 'Measurement' should pass."""
        sql = """
        SELECT m.measurement_concept_id
        FROM measurement m
        JOIN concept c ON m.measurement_concept_id = c.concept_id
        WHERE c.domain_id = 'Measurement'
        """
        errors = self._run_rule(sql)
        assert errors == []

    def test_domain_filter_in_join_on(self) -> None:
        """domain_id filter in JOIN ON clause should pass."""
        sql = """
        SELECT co.condition_concept_id
        FROM condition_occurrence co
        JOIN concept c
            ON co.condition_concept_id = c.concept_id
            AND c.domain_id = 'Condition'
        """
        errors = self._run_rule(sql)
        assert errors == []

    def test_domain_filter_in_clause(self) -> None:
        """domain_id IN (...) with correct domain should pass."""
        sql = """
        SELECT co.condition_concept_id
        FROM condition_occurrence co
        JOIN concept c ON co.condition_concept_id = c.concept_id
        WHERE c.domain_id IN ('Condition')
        """
        errors = self._run_rule(sql)
        assert errors == []

    def test_death_cause_concept_uses_condition_domain(self) -> None:
        """death.cause_concept_id maps to 'Condition' domain and should pass with it."""
        sql = """
        SELECT d.cause_concept_id
        FROM death d
        JOIN concept c ON d.cause_concept_id = c.concept_id
        WHERE c.domain_id = 'Condition'
        """
        errors = self._run_rule(sql)
        assert errors == []

    # --- Wrong domain filter -> ERROR ---

    def test_condition_occurrence_wrong_domain_procedure(self) -> None:
        """condition_occurrence filtered with domain_id = 'Procedure' should ERROR."""
        sql = """
        SELECT co.condition_concept_id
        FROM condition_occurrence co
        JOIN concept c ON co.condition_concept_id = c.concept_id
        WHERE c.domain_id = 'Procedure'
        """
        errors = self._run_rule(sql)
        assert len(errors) > 0
        errors_only = [e for e in errors if e.startswith("Error:")]
        assert len(errors_only) > 0
        assert any("domain mismatch" in e.lower() for e in errors_only)
        assert any("condition_occurrence" in e for e in errors_only)

    def test_drug_exposure_wrong_domain_condition(self) -> None:
        """drug_exposure filtered with domain_id = 'Condition' should ERROR."""
        sql = """
        SELECT de.drug_concept_id
        FROM drug_exposure de
        JOIN concept c ON de.drug_concept_id = c.concept_id
        WHERE c.domain_id = 'Condition'
        """
        errors = self._run_rule(sql)
        errors_only = [e for e in errors if e.startswith("Error:")]
        assert len(errors_only) > 0
        assert any("drug_exposure" in e for e in errors_only)

    def test_procedure_wrong_domain_drug(self) -> None:
        """procedure_occurrence filtered with domain_id = 'Drug' should ERROR."""
        sql = """
        SELECT po.procedure_concept_id
        FROM procedure_occurrence po
        JOIN concept c ON po.procedure_concept_id = c.concept_id
        WHERE c.domain_id = 'Drug'
        """
        errors = self._run_rule(sql)
        errors_only = [e for e in errors if e.startswith("Error:")]
        assert len(errors_only) > 0

    def test_visit_occurrence_wrong_domain(self) -> None:
        """visit_occurrence filtered with domain_id = 'Condition' should ERROR."""
        sql = """
        SELECT vo.visit_concept_id
        FROM visit_occurrence vo
        JOIN concept c ON vo.visit_concept_id = c.concept_id
        WHERE c.domain_id = 'Condition'
        """
        errors = self._run_rule(sql)
        errors_only = [e for e in errors if e.startswith("Error:")]
        assert len(errors_only) > 0

    def test_death_wrong_domain(self) -> None:
        """death.cause_concept_id filtered with domain_id = 'Drug' (not Condition) should ERROR."""
        sql = """
        SELECT d.cause_concept_id
        FROM death d
        JOIN concept c ON d.cause_concept_id = c.concept_id
        WHERE c.domain_id = 'Drug'
        """
        errors = self._run_rule(sql)
        errors_only = [e for e in errors if e.startswith("Error:")]
        assert len(errors_only) > 0

    # --- No domain filter -> WARNING ---

    def test_no_domain_filter_warns(self) -> None:
        """concept join without domain_id filter should produce an ERROR."""
        sql = """
        SELECT co.condition_concept_id
        FROM condition_occurrence co
        JOIN concept c ON co.condition_concept_id = c.concept_id
        WHERE c.standard_concept = 'S'
        """
        errors = self._run_rule(sql)
        warnings_only = [e for e in errors if e.startswith("Warning:")]
        assert len(warnings_only) > 0  # Best practice, not error

    def test_no_domain_filter_drug_warns(self) -> None:
        """drug_exposure join to concept without domain_id should produce an ERROR."""
        sql = """
        SELECT de.drug_concept_id
        FROM drug_exposure de
        JOIN concept c ON de.drug_concept_id = c.concept_id
        WHERE c.invalid_reason IS NULL
        """
        errors = self._run_rule(sql)
        warnings_only = [e for e in errors if e.startswith("Warning:")]
        assert len(warnings_only) > 0  # Best practice, not error

    # --- No concept table -> no violation ---

    def test_no_concept_table_no_violation(self) -> None:
        """Query without concept table should not trigger the rule."""
        sql = """
        SELECT co.person_id, co.condition_concept_id
        FROM condition_occurrence co
        WHERE co.condition_concept_id IN (201826, 201254)
        """
        errors = self._run_rule(sql)
        assert errors == []

    def test_clinical_tables_only_no_violation(self) -> None:
        """Query joining only clinical tables should not trigger the rule."""
        sql = """
        SELECT co.person_id
        FROM condition_occurrence co
        JOIN drug_exposure de ON co.person_id = de.person_id
        WHERE co.condition_start_date > '2020-01-01'
        """
        errors = self._run_rule(sql)
        assert errors == []

    # --- Multiple tables ---

    def test_multiple_tables_both_correct(self) -> None:
        """Two clinical tables each with correct domain filters should pass."""
        sql = """
        SELECT co.person_id
        FROM condition_occurrence co
        JOIN drug_exposure de ON co.person_id = de.person_id
        JOIN concept cc ON co.condition_concept_id = cc.concept_id
            AND cc.domain_id = 'Condition'
        JOIN concept dc ON de.drug_concept_id = dc.concept_id
            AND dc.domain_id = 'Drug'
        WHERE cc.standard_concept = 'S'
        AND dc.standard_concept = 'S'
        """
        errors = self._run_rule(sql)
        assert errors == []

    def test_unrelated_concept_column_not_flagged(self) -> None:
        """Joining concept on a type_concept_id (not a primary entity column) should not trigger."""
        sql = """
        SELECT co.condition_type_concept_id
        FROM condition_occurrence co
        JOIN concept c ON co.condition_type_concept_id = c.concept_id
        WHERE c.standard_concept = 'S'
        """
        errors = self._run_rule(sql)
        # type_concept_id is not in CLINICAL_TABLE_DOMAIN -> no domain segregation violation
        errors_only = [e for e in errors if e.startswith("Error:")]
        assert errors_only == []

    def test_cte_concept_join_not_flagged(self) -> None:
        """Joining to a CTE (not directly to concept table) should not trigger."""
        sql = """
        WITH condition_concepts AS (
            SELECT concept_id
            FROM concept
            WHERE domain_id = 'Drug'
        )
        SELECT co.condition_concept_id
        FROM condition_occurrence co
        JOIN condition_concepts cc ON co.condition_concept_id = cc.concept_id
        """
        errors = self._run_rule(sql)
        # The clinical table joins a CTE, not concept directly -> no domain_segregation violation
        errors_only = [e for e in errors if e.startswith("Error:")]
        assert errors_only == []


class TestMeasurementUnitValidation:
    """Tests for the measurement unit validation rule."""

    def _run_rule(self, sql: str, dialect: str = "postgres") -> list:
        from fastssv.core.registry import get_rule
        rule = get_rule("domain_specific.measurement_unit_validation")()
        return rule.validate(sql, dialect)

    def test_value_as_number_without_unit_fires(self) -> None:
        """Filtering value_as_number without unit_concept_id -> violation."""
        sql = """
        SELECT m.person_id
        FROM measurement m
        WHERE m.measurement_concept_id = 3004410
          AND m.value_as_number > 7.0
        """
        violations = self._run_rule(sql)
        assert len(violations) > 0
        assert violations[0].rule_id == "domain_specific.measurement_unit_validation"

    def test_value_as_number_with_unit_passes(self) -> None:
        """Filtering value_as_number WITH unit_concept_id -> no violation."""
        sql = """
        SELECT m.person_id
        FROM measurement m
        WHERE m.measurement_concept_id = 3004410
          AND m.value_as_number > 7.0
          AND m.unit_concept_id = 8554
        """
        violations = self._run_rule(sql)
        assert violations == []

    def test_no_value_as_number_filter_not_flagged(self) -> None:
        """Measurement query without numeric threshold -> no violation."""
        sql = """
        SELECT m.person_id, m.value_as_number
        FROM measurement m
        WHERE m.measurement_concept_id = 3004410
        """
        violations = self._run_rule(sql)
        assert violations == []

    def test_non_measurement_table_not_flagged(self) -> None:
        """Numeric comparison on non-measurement table -> no violation."""
        sql = """
        SELECT person_id
        FROM condition_occurrence
        WHERE condition_occurrence_id > 100
        """
        violations = self._run_rule(sql)
        assert violations == []

    def test_gte_comparison_without_unit_fires(self) -> None:
        """GTE (>=) threshold without unit_concept_id also triggers the rule."""
        sql = """
        SELECT m.person_id
        FROM measurement m
        WHERE m.value_as_number >= 6.5
        """
        violations = self._run_rule(sql)
        assert len(violations) > 0

