class TestMeasurementDuplicateDetection:
    """Tests for measurement duplicate detection rule (OMOP_238)."""

    def _run_rule(self, sql: str, dialect: str = "postgres") -> list:
        from fastssv.core.registry import get_rule
        rule = get_rule("domain_specific.measurement_duplicate_detection")()
        return rule.validate(sql, dialect)

    def test_omop_238_count_without_natural_key_violation(self) -> None:
        """Counting measurements without natural key grouping should trigger WARNING."""
        sql = """
        SELECT measurement_concept_id, COUNT(*) AS measurement_count
        FROM measurement
        WHERE measurement_concept_id = 3004410
        GROUP BY measurement_concept_id
        """
        violations = self._run_rule(sql)
        assert len(violations) == 1
        assert "duplicate" in violations[0].message.lower()
        assert "natural key" in violations[0].message.lower()
        from fastssv.core.base import Severity

    def test_omop_238_avg_without_date_grouping_violation(self) -> None:
        """Averaging without date in GROUP BY should trigger WARNING."""
        sql = """
        SELECT person_id, AVG(value_as_number) AS avg_glucose
        FROM measurement
        WHERE measurement_concept_id = 3004410
        GROUP BY person_id
        """
        violations = self._run_rule(sql)
        assert len(violations) == 1
        assert "duplicate" in violations[0].message.lower()

    def test_omop_238_count_star_violation(self) -> None:
        """COUNT(*) without deduplication should trigger WARNING."""
        sql = """
        SELECT COUNT(*) AS total_measurements
        FROM measurement
        WHERE measurement_concept_id = 3004410
        """
        violations = self._run_rule(sql)
        assert len(violations) == 1

    def test_omop_238_sum_without_dedup_violation(self) -> None:
        """SUM without natural key grouping should trigger WARNING."""
        sql = """
        SELECT person_id, SUM(value_as_number) AS total_value
        FROM measurement
        WHERE measurement_concept_id = 3004410
        GROUP BY person_id
        """
        violations = self._run_rule(sql)
        assert len(violations) == 1

    def test_omop_238_natural_key_grouping_correct(self) -> None:
        """Grouping by natural key should pass (no violation)."""
        sql = """
        SELECT person_id, measurement_date, measurement_concept_id,
               AVG(value_as_number) AS avg_value
        FROM measurement
        WHERE measurement_concept_id = 3004410
        GROUP BY person_id, measurement_date, measurement_concept_id
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_omop_238_with_distinct_correct(self) -> None:
        """Using DISTINCT should pass (no violation)."""
        sql = """
        SELECT DISTINCT person_id, measurement_concept_id, measurement_date
        FROM measurement
        WHERE measurement_concept_id = 3004410
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_omop_238_with_row_number_correct(self) -> None:
        """Using ROW_NUMBER for deduplication should pass."""
        sql = """
        WITH ranked AS (
          SELECT *,
            ROW_NUMBER() OVER (
              PARTITION BY person_id, measurement_concept_id, measurement_date
              ORDER BY measurement_datetime NULLS LAST
            ) AS rn
          FROM measurement
        )
        SELECT * FROM ranked WHERE rn = 1
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_omop_238_single_person_query_correct(self) -> None:
        """Query for single person has low duplicate risk - should pass."""
        sql = """
        SELECT AVG(value_as_number) AS avg_glucose
        FROM measurement
        WHERE person_id = 123456
          AND measurement_concept_id = 3004410
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_omop_238_with_measurement_datetime_filter_correct(self) -> None:
        """Using measurement_datetime in WHERE suggests time precision - should pass."""
        sql = """
        SELECT person_id, AVG(value_as_number) AS avg_glucose
        FROM measurement
        WHERE measurement_datetime BETWEEN '2023-01-01' AND '2023-12-31'
          AND measurement_concept_id = 3004410
        GROUP BY person_id
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_omop_238_no_aggregation_correct(self) -> None:
        """Query without aggregation should pass."""
        sql = """
        SELECT person_id, measurement_date, value_as_number
        FROM measurement
        WHERE measurement_concept_id = 3004410
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_omop_238_no_measurement_table_correct(self) -> None:
        """Query without measurement table should pass."""
        sql = """
        SELECT person_id, COUNT(*) AS observation_count
        FROM observation
        GROUP BY person_id
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_omop_238_count_distinct_person_id_violation(self) -> None:
        """COUNT(DISTINCT person_id) without date grouping should still warn."""
        sql = """
        SELECT measurement_concept_id, COUNT(DISTINCT person_id) AS patient_count
        FROM measurement
        GROUP BY measurement_concept_id
        """
        violations = self._run_rule(sql)
        # This is a borderline case - COUNT(DISTINCT person_id) might be intentional
        # but still sensitive to duplicates at different granularity
        assert len(violations) == 1

    def test_omop_238_with_rank_dedup_correct(self) -> None:
        """Using RANK for deduplication should pass."""
        sql = """
        WITH ranked AS (
          SELECT *,
            RANK() OVER (
              PARTITION BY person_id, measurement_concept_id, measurement_date
              ORDER BY value_as_number DESC
            ) AS rnk
          FROM measurement
        )
        SELECT * FROM ranked WHERE rnk = 1
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_omop_238_multiple_aggregations_violation(self) -> None:
        """Multiple aggregations without natural key should trigger WARNING."""
        sql = """
        SELECT
          person_id,
          COUNT(*) AS n_measurements,
          AVG(value_as_number) AS avg_value,
          MIN(value_as_number) AS min_value
        FROM measurement
        WHERE measurement_concept_id = 3004410
        GROUP BY person_id
        """
        violations = self._run_rule(sql)
        assert len(violations) == 1

    def test_omop_238_aliased_table_violation(self) -> None:
        """Should detect violations with aliased measurement table."""
        sql = """
        SELECT m.person_id, AVG(m.value_as_number) AS avg_glucose
        FROM measurement m
        WHERE m.measurement_concept_id = 3004410
        GROUP BY m.person_id
        """
        violations = self._run_rule(sql)
        assert len(violations) == 1

    def test_omop_238_join_with_natural_key_correct(self) -> None:
        """Join with proper grouping should pass."""
        sql = """
        SELECT p.person_id, m.measurement_date, m.measurement_concept_id,
               AVG(m.value_as_number) AS avg_value
        FROM person p
        JOIN measurement m ON p.person_id = m.person_id
        WHERE m.measurement_concept_id = 3004410
        GROUP BY p.person_id, m.measurement_date, m.measurement_concept_id
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0


class TestClinicalPersonIdLinkageValidation:
    """Tests for CLIN_055, OMOP_517: clinical tables require person_id linkage."""

    def _run_rule(self, sql: str) -> list:
        """Run clinical person_id linkage validation rule."""
        from fastssv.core.registry import get_rule
        rule = get_rule("joins.clinical_person_id_linkage_validation")()
        return rule.validate(sql)

    # CLIN_055: Clinical tables must be linked via person_id

    def test_clin_055_no_person_id_linkage_fires(self):
        """Test that joining clinical tables without person_id fires."""
        sql = """
        SELECT co.condition_concept_id, de.drug_concept_id
        FROM condition_occurrence co
        JOIN drug_exposure de ON co.condition_start_date = de.drug_exposure_start_date
        """
        violations = self._run_rule(sql)
        assert len(violations) == 1
        assert "person_id" in violations[0].message.lower()
        assert "condition_occurrence" in violations[0].message
        assert "drug_exposure" in violations[0].message

    def test_clin_055_direct_person_id_join_passes(self):
        """Test that direct person_id join passes."""
        sql = """
        SELECT co.condition_concept_id, de.drug_concept_id
        FROM condition_occurrence co
        JOIN drug_exposure de ON co.person_id = de.person_id
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_clin_055_transitive_person_id_passes(self):
        """Test that transitive person_id linkage through person table passes."""
        sql = """
        SELECT co.condition_concept_id, de.drug_concept_id
        FROM condition_occurrence co
        JOIN person p ON co.person_id = p.person_id
        JOIN drug_exposure de ON p.person_id = de.person_id
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_clin_055_three_tables_all_linked_passes(self):
        """Test that 3 clinical tables all linked via person_id passes."""
        sql = """
        SELECT *
        FROM condition_occurrence co
        JOIN drug_exposure de ON co.person_id = de.person_id
        JOIN procedure_occurrence po ON co.person_id = po.person_id
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_clin_055_three_tables_partial_linkage_fires(self):
        """Test that 3 tables with only partial person_id linkage fires."""
        sql = """
        SELECT *
        FROM condition_occurrence co
        JOIN drug_exposure de ON co.person_id = de.person_id
        JOIN procedure_occurrence po ON co.condition_start_date = po.procedure_date
        """
        violations = self._run_rule(sql)
        # procedure_occurrence not linked via person_id to the others
        assert len(violations) > 0

    def test_clin_055_single_clinical_table_passes(self):
        """Test that a single clinical table passes (no joins to validate)."""
        sql = """
        SELECT * FROM condition_occurrence
        WHERE condition_concept_id = 123
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_clin_055_clinical_with_vocabulary_passes(self):
        """Test that joining clinical to vocabulary tables passes (no validation)."""
        sql = """
        SELECT co.*, c.concept_name
        FROM condition_occurrence co
        JOIN concept c ON co.condition_concept_id = c.concept_id
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_clin_055_using_person_id_passes(self):
        """Test that USING(person_id) is recognized as valid linkage."""
        sql = """
        SELECT *
        FROM condition_occurrence co
        JOIN drug_exposure de USING(person_id)
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_clin_055_where_clause_join_fires(self):
        """Test that implicit joins via WHERE without person_id fire."""
        sql = """
        SELECT *
        FROM condition_occurrence co, drug_exposure de
        WHERE co.condition_start_date = de.drug_exposure_start_date
        """
        violations = self._run_rule(sql)
        assert len(violations) == 1

    def test_clin_055_where_clause_person_id_passes(self):
        """Test that implicit joins via WHERE with person_id pass."""
        sql = """
        SELECT *
        FROM condition_occurrence co, drug_exposure de
        WHERE co.person_id = de.person_id
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_clin_055_qualified_columns_fires(self):
        """Test that qualified column names are handled correctly."""
        sql = """
        SELECT co.condition_concept_id, de.drug_concept_id
        FROM condition_occurrence co
        JOIN drug_exposure de ON co.visit_occurrence_id = de.visit_occurrence_id
        """
        violations = self._run_rule(sql)
        # Joined on visit_occurrence_id, not person_id
        assert len(violations) == 1

    def test_clin_055_measurement_observation_no_linkage_fires(self):
        """Test other clinical table combinations."""
        sql = """
        SELECT m.measurement_concept_id, o.observation_concept_id
        FROM measurement m
        JOIN observation o ON m.measurement_date = o.observation_date
        """
        violations = self._run_rule(sql)
        assert len(violations) == 1

    def test_clin_055_visit_detail_visit_occurrence_linkage(self):
        """Test visit_detail and visit_occurrence joined without person_id."""
        sql = """
        SELECT vd.*, vo.visit_concept_id
        FROM visit_detail vd
        JOIN visit_occurrence vo ON vd.visit_occurrence_id = vo.visit_occurrence_id
        """
        violations = self._run_rule(sql)
        # Both are clinical tables but joined on visit_occurrence_id, not person_id
        assert len(violations) == 1

    def test_clin_055_death_person_join_fires(self):
        """Test death table joined to person without person_id."""
        sql = """
        SELECT d.*, p.gender_concept_id
        FROM death d
        JOIN person p ON d.death_date = p.birth_datetime
        """
        violations = self._run_rule(sql)
        assert len(violations) == 1


