class TestCommaSeparatedCrossJoin:
    """Tests for GAP_035: comma_separated_cross_join."""

    def _run_rule(self, sql: str, dialect: str = "postgres") -> list:
        from fastssv.core.registry import get_rule
        rule = get_rule("anti_patterns.comma_separated_cross_join")()
        return rule.validate(sql, dialect)

    # --- Violation tests ---

    def test_gap_035_two_clinical_tables_no_join(self) -> None:
        """GAP_035: Two clinical tables with comma, no join condition should error."""
        sql = """
        SELECT * FROM condition_occurrence, drug_exposure
        WHERE condition_concept_id = 201826
        """
        violations = self._run_rule(sql)
        assert len(violations) > 0
        assert "condition_occurrence" in violations[0].message
        assert "drug_exposure" in violations[0].message
        assert violations[0].severity == Severity.ERROR

    def test_gap_035_three_clinical_tables_no_join(self) -> None:
        """GAP_035: Three clinical tables with commas, no join should error."""
        sql = """
        SELECT * FROM condition_occurrence, drug_exposure, measurement
        WHERE condition_concept_id = 201826
        """
        violations = self._run_rule(sql)
        assert len(violations) > 0

    def test_gap_035_clinical_and_person_no_join(self) -> None:
        """GAP_035: Clinical table and person with comma, no join should error."""
        sql = """
        SELECT * FROM condition_occurrence co, person p
        WHERE co.condition_concept_id = 201826
        """
        violations = self._run_rule(sql)
        assert len(violations) > 0

    def test_gap_035_with_aliases_no_join(self) -> None:
        """GAP_035: Aliased tables with comma, no join should error."""
        sql = """
        SELECT co.person_id, de.drug_concept_id
        FROM condition_occurrence co, drug_exposure de
        WHERE co.condition_concept_id = 201826
        """
        violations = self._run_rule(sql)
        assert len(violations) > 0

    # --- Correct pattern tests ---

    def test_gap_035_with_where_join_condition(self) -> None:
        """GAP_035: Comma-separated with WHERE join condition should pass."""
        sql = """
        SELECT * FROM condition_occurrence co, drug_exposure de
        WHERE co.person_id = de.person_id
          AND co.condition_concept_id = 201826
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_gap_035_with_explicit_join(self) -> None:
        """GAP_035: Explicit JOIN...ON should pass."""
        sql = """
        SELECT * FROM condition_occurrence co
        JOIN drug_exposure de ON co.person_id = de.person_id
        WHERE co.condition_concept_id = 201826
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_gap_035_single_table(self) -> None:
        """GAP_035: Single table query should pass."""
        sql = """
        SELECT * FROM condition_occurrence WHERE condition_concept_id = 201826
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_gap_035_vocabulary_tables_cross_join(self) -> None:
        """GAP_035: Small vocabulary table cross joins should pass."""
        sql = """
        SELECT * FROM concept c1, concept c2
        WHERE c1.vocabulary_id = 'SNOMED' AND c2.vocabulary_id = 'LOINC'
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_gap_035_left_join(self) -> None:
        """GAP_035: LEFT JOIN should pass."""
        sql = """
        SELECT * FROM condition_occurrence co
        LEFT JOIN drug_exposure de ON co.person_id = de.person_id
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_gap_035_multiple_join_conditions(self) -> None:
        """GAP_035: Multiple join conditions in WHERE should pass."""
        sql = """
        SELECT * FROM condition_occurrence co, drug_exposure de, measurement m
        WHERE co.person_id = de.person_id
          AND de.person_id = m.person_id
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_gap_035_mixed_join_styles(self) -> None:
        """GAP_035: Mixed explicit JOIN and comma should detect unjoined table."""
        sql = """
        SELECT * FROM condition_occurrence co
        JOIN drug_exposure de ON co.person_id = de.person_id, measurement m
        """
        violations = self._run_rule(sql)
        # measurement is not joined to co or de
        assert len(violations) > 0


# --- GAP_036: UNION vs UNION ALL for Clinical Events ---


class TestUnionVsUnionAllClinicalEvents:
    """Tests for GAP_036 - UNION vs UNION ALL for clinical event tables."""

    def _run_rule(self, sql: str, dialect: str = "postgres") -> list:
        from fastssv.rules.data_quality.union_vs_union_all_clinical_events import (
            UnionVsUnionAllClinicalEventsRule,
        )

        rule = UnionVsUnionAllClinicalEventsRule()
        return rule.validate(sql, dialect)

    def test_gap_036_union_without_all_clinical_events(self) -> None:
        """GAP_036: UNION without ALL for clinical events should fail."""
        sql = """
        SELECT person_id, condition_start_date AS event_date
        FROM condition_occurrence
        WHERE condition_concept_id = 201826
        UNION
        SELECT person_id, drug_exposure_start_date
        FROM drug_exposure
        WHERE drug_concept_id = 1125315
        """
        violations = self._run_rule(sql)
        assert len(violations) == 1
        assert "union_without_all_clinical_events" in violations[0].details["issue"]

    def test_gap_036_union_all_clinical_events(self) -> None:
        """GAP_036: UNION ALL for clinical events should pass."""
        sql = """
        SELECT person_id, condition_start_date AS event_date
        FROM condition_occurrence
        WHERE condition_concept_id = 201826
        UNION ALL
        SELECT person_id, drug_exposure_start_date
        FROM drug_exposure
        WHERE drug_concept_id = 1125315
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_gap_036_union_without_all_visits(self) -> None:
        """GAP_036: UNION without ALL for visit tables should fail."""
        sql = """
        SELECT person_id, visit_start_date
        FROM visit_occurrence
        WHERE visit_concept_id = 9203
        UNION
        SELECT person_id, visit_start_date
        FROM visit_detail
        WHERE visit_detail_concept_id = 9201
        """
        violations = self._run_rule(sql)
        assert len(violations) == 1

    def test_gap_036_union_without_all_vocabulary_tables(self) -> None:
        """GAP_036: UNION without ALL for vocabulary tables should pass."""
        sql = """
        SELECT concept_id, concept_name
        FROM concept
        WHERE vocabulary_id = 'SNOMED'
        UNION
        SELECT concept_id, concept_name
        FROM concept
        WHERE vocabulary_id = 'LOINC'
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_gap_036_multiple_unions_mixed(self) -> None:
        """GAP_036: Multiple UNIONs with mixed ALL/non-ALL should flag non-ALL."""
        sql = """
        SELECT person_id, condition_start_date AS event_date
        FROM condition_occurrence
        WHERE condition_concept_id = 201826
        UNION ALL
        SELECT person_id, drug_exposure_start_date
        FROM drug_exposure
        WHERE drug_concept_id = 1125315
        UNION
        SELECT person_id, procedure_date
        FROM procedure_occurrence
        WHERE procedure_concept_id = 4301351
        """
        violations = self._run_rule(sql)
        # Should detect the second UNION (without ALL)
        assert len(violations) == 1

    def test_gap_036_person_id_only_cohort_union_suppressed(self) -> None:
        """GAP_036: UNION over person_id-only arms is cohort set-union, not event combination."""
        sql = """
        SELECT DISTINCT person_id FROM condition_occurrence co
        WHERE co.condition_concept_id IN (320128)
        UNION
        SELECT DISTINCT person_id FROM drug_exposure de
        WHERE de.drug_concept_id IN (1338512)
        UNION
        SELECT DISTINCT person_id FROM condition_occurrence co2
        WHERE co2.condition_concept_id IN (4326962)
        """
        violations = self._run_rule(sql)
        assert violations == []

    def test_gap_036_person_id_only_qualified_and_aliased(self) -> None:
        """GAP_036: Qualified (co.person_id) and aliased (AS person_id) arms still treated as cohort."""
        sql = """
        SELECT co.person_id FROM condition_occurrence co
        WHERE co.condition_concept_id = 201826
        UNION
        SELECT de.person_id AS person_id FROM drug_exposure de
        WHERE de.drug_concept_id = 1125315
        """
        violations = self._run_rule(sql)
        assert violations == []

    def test_gap_036_person_id_plus_date_still_flagged(self) -> None:
        """GAP_036: Adding an event column (date) reintroduces event-loss risk — must still flag."""
        sql = """
        SELECT person_id, condition_start_date
        FROM condition_occurrence
        WHERE condition_concept_id = 201826
        UNION
        SELECT person_id, drug_exposure_start_date
        FROM drug_exposure
        WHERE drug_concept_id = 1125315
        """
        violations = self._run_rule(sql)
        assert len(violations) == 1

    def test_gap_036_union_without_all_measurement(self) -> None:
        """GAP_036: UNION without ALL for measurement table should fail."""
        sql = """
        SELECT person_id, measurement_date
        FROM measurement
        WHERE measurement_concept_id = 3004249
        UNION
        SELECT person_id, observation_date
        FROM observation
        WHERE observation_concept_id = 4013886
        """
        violations = self._run_rule(sql)
        assert len(violations) == 1

    def test_gap_036_union_all_multiple_clinical_events(self) -> None:
        """GAP_036: UNION ALL for multiple clinical event tables should pass."""
        sql = """
        SELECT person_id, condition_start_date AS event_date
        FROM condition_occurrence
        UNION ALL
        SELECT person_id, drug_exposure_start_date
        FROM drug_exposure
        UNION ALL
        SELECT person_id, procedure_date
        FROM procedure_occurrence
        UNION ALL
        SELECT person_id, measurement_date
        FROM measurement
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_gap_036_union_without_all_episode(self) -> None:
        """GAP_036: UNION without ALL for episode table should fail."""
        sql = """
        SELECT person_id, episode_start_date
        FROM episode
        WHERE episode_concept_id = 32533
        UNION
        SELECT person_id, episode_start_date
        FROM episode
        WHERE episode_concept_id = 32534
        """
        violations = self._run_rule(sql)
        assert len(violations) == 1

    def test_gap_036_union_without_all_device_exposure(self) -> None:
        """GAP_036: UNION without ALL for device_exposure should fail."""
        sql = """
        SELECT person_id, device_exposure_start_date
        FROM device_exposure
        WHERE device_concept_id = 4324879
        UNION
        SELECT person_id, device_exposure_start_date
        FROM device_exposure
        WHERE device_concept_id = 4324880
        """
        violations = self._run_rule(sql)
        assert len(violations) == 1

    def test_gap_036_union_all_specimen_note(self) -> None:
        """GAP_036: UNION ALL for specimen and note tables should pass."""
        sql = """
        SELECT person_id, specimen_date
        FROM specimen
        WHERE specimen_concept_id = 4034850
        UNION ALL
        SELECT person_id, note_date
        FROM note
        WHERE note_type_concept_id = 44814645
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_gap_036_single_select_no_union(self) -> None:
        """GAP_036: Single SELECT without UNION should pass."""
        sql = """
        SELECT person_id, condition_start_date
        FROM condition_occurrence
        WHERE condition_concept_id = 201826
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_gap_036_union_without_all_subquery(self) -> None:
        """GAP_036: UNION without ALL in subquery should be detected."""
        sql = """
        SELECT * FROM (
            SELECT person_id, condition_start_date AS event_date
            FROM condition_occurrence
            UNION
            SELECT person_id, drug_exposure_start_date
            FROM drug_exposure
        ) events
        WHERE event_date > '2020-01-01'
        """
        violations = self._run_rule(sql)
        assert len(violations) == 1


# --- GAP_037: Ambiguous Column Reference ---


class TestAmbiguousColumnReference:
    """Tests for GAP_037 - Ambiguous column reference in multi-table queries."""

    def _run_rule(self, sql: str, dialect: str = "postgres") -> list:
        from fastssv.rules.anti_patterns.ambiguous_column_reference import (
            AmbiguousColumnReferenceRule,
        )

        rule = AmbiguousColumnReferenceRule()
        return rule.validate(sql, dialect)

    def test_gap_037_unqualified_person_id_in_where(self) -> None:
        """GAP_037: Unqualified person_id in WHERE should warn."""
        sql = """
        SELECT co.person_id, co.condition_concept_id
        FROM condition_occurrence co
        JOIN person p ON co.person_id = p.person_id
        WHERE person_id = 12345
        """
        violations = self._run_rule(sql)
        assert len(violations) == 1
        assert "person_id" in violations[0].message.lower()
        assert "ambiguous" in violations[0].message.lower()

    def test_gap_037_unqualified_person_id_in_select(self) -> None:
        """GAP_037: Unqualified person_id in SELECT should warn."""
        sql = """
        SELECT person_id, condition_concept_id
        FROM condition_occurrence co
        JOIN person p ON co.person_id = p.person_id
        WHERE co.person_id = 12345
        """
        violations = self._run_rule(sql)
        assert len(violations) == 1

    def test_gap_037_qualified_columns(self) -> None:
        """GAP_037: Fully qualified columns should pass."""
        sql = """
        SELECT co.person_id, co.condition_concept_id
        FROM condition_occurrence co
        JOIN person p ON co.person_id = p.person_id
        WHERE co.person_id = 12345
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_gap_037_single_table_query(self) -> None:
        """GAP_037: Single table queries cannot have ambiguous columns."""
        sql = """
        SELECT person_id, condition_concept_id
        FROM condition_occurrence
        WHERE person_id = 12345
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_gap_037_unqualified_provider_id(self) -> None:
        """GAP_037: Unqualified provider_id should warn."""
        sql = """
        SELECT provider_id, COUNT(*)
        FROM drug_exposure de
        JOIN provider pr ON de.provider_id = pr.provider_id
        GROUP BY provider_id
        """
        violations = self._run_rule(sql)
        assert len(violations) == 1
        assert "provider_id" in violations[0].message.lower()

    def test_gap_037_unqualified_care_site_id(self) -> None:
        """GAP_037: Unqualified care_site_id should warn."""
        sql = """
        SELECT care_site_id, visit_start_date
        FROM visit_occurrence vo
        JOIN care_site cs ON vo.care_site_id = cs.care_site_id
        WHERE care_site_id = 100
        """
        violations = self._run_rule(sql)
        assert len(violations) == 1
        assert "care_site_id" in violations[0].message.lower()

    def test_gap_037_unqualified_visit_occurrence_id(self) -> None:
        """GAP_037: Unqualified visit_occurrence_id should warn."""
        sql = """
        SELECT visit_occurrence_id, condition_concept_id
        FROM condition_occurrence co
        JOIN visit_occurrence vo ON co.visit_occurrence_id = vo.visit_occurrence_id
        WHERE visit_occurrence_id = 500
        """
        violations = self._run_rule(sql)
        assert len(violations) == 1

    def test_gap_037_unqualified_visit_detail_id(self) -> None:
        """GAP_037: Unqualified visit_detail_id should warn."""
        sql = """
        SELECT visit_detail_id, measurement_concept_id
        FROM measurement m
        JOIN visit_detail vd ON m.visit_detail_id = vd.visit_detail_id
        ORDER BY visit_detail_id
        """
        violations = self._run_rule(sql)
        assert len(violations) == 1

    def test_gap_037_multiple_unqualified_columns(self) -> None:
        """GAP_037: Multiple unqualified ambiguous columns should warn once each."""
        sql = """
        SELECT person_id, provider_id, condition_concept_id
        FROM condition_occurrence co
        JOIN person p ON co.person_id = p.person_id
        JOIN provider pr ON co.provider_id = pr.provider_id
        WHERE person_id = 12345 AND provider_id = 100
        """
        violations = self._run_rule(sql)
        # Should detect both person_id and provider_id (deduplicated)
        assert len(violations) == 2

    def test_gap_037_mixed_qualified_unqualified(self) -> None:
        """GAP_037: Mix of qualified and unqualified should warn on unqualified."""
        sql = """
        SELECT co.person_id, provider_id, co.condition_concept_id
        FROM condition_occurrence co
        JOIN provider pr ON co.provider_id = pr.provider_id
        WHERE co.person_id = 12345
        """
        violations = self._run_rule(sql)
        # Only provider_id is unqualified
        assert len(violations) == 1
        assert "provider_id" in violations[0].message.lower()

    def test_gap_037_join_on_clause_excluded(self) -> None:
        """GAP_037: JOIN ON clauses should not trigger warnings (always qualified)."""
        sql = """
        SELECT co.person_id, co.condition_concept_id
        FROM condition_occurrence co
        JOIN person p ON person_id = person_id
        WHERE co.person_id = 12345
        """
        violations = self._run_rule(sql)
        # JOIN ON uses unqualified, but that's a different error (not ambiguous reference)
        # Our rule should not flag JOIN ON clauses
        assert len(violations) == 0

    def test_gap_037_three_table_join(self) -> None:
        """GAP_037: Three table joins with unqualified columns."""
        sql = """
        SELECT person_id, condition_concept_id, drug_concept_id
        FROM condition_occurrence co
        JOIN person p ON co.person_id = p.person_id
        JOIN drug_exposure de ON p.person_id = de.person_id
        WHERE person_id = 12345
        """
        violations = self._run_rule(sql)
        assert len(violations) == 1
        assert "person_id" in violations[0].message.lower()

    def test_gap_037_subquery_single_table(self) -> None:
        """GAP_037: Subquery with single table should not warn."""
        sql = """
        SELECT *
        FROM (
            SELECT person_id, condition_concept_id
            FROM condition_occurrence
            WHERE person_id = 12345
        ) sub
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0

    def test_gap_037_non_ambiguous_column(self) -> None:
        """GAP_037: Non-ambiguous columns should not warn."""
        sql = """
        SELECT condition_concept_id, condition_start_date
        FROM condition_occurrence co
        JOIN person p ON co.person_id = p.person_id
        WHERE condition_concept_id = 201826
        """
        violations = self._run_rule(sql)
        assert len(violations) == 0


